    tasks <- i
  }
  close(tasks)
}

func worker(id int, wg *sync.WaitGroup) {
  defer wg.Done()
  // perform task
  fmt.Printf("worker %d done\n", id)
}
func main() {
  var wg sync.WaitGroup
  for i := 0; i < 5; i++ {
    wg.Add(1)
    go worker(i, &wg)
  }
  wg.Wait()
}

type Worker struct {
  tasks chan func()
  quit  chan bool
}
func NewWorker() *Worker {
  w := &Worker{
    tasks: make(chan func()),
    quit:  make(chan bool),
  }
  go func() {
    for {
      select {
      case task := <-w.tasks:
        task()
      case <-w.quit:
        return
      }
    }
  }()
  return w
}

func worker(ctx context.Context) {
  for {
    select {
    case <-ctx.Done():
      return
    default:
      // perform task
      fmt.Println("worker running")
      time.Sleep(time.Second)
    }
  }
}
func main() {
  ctx, cancel := context.WithCancel(context.Background())
  go worker(ctx)
  time.Sleep(5 * time.Second)
  cancel()
}

