  FROM sales_data
  GROUP BY region, product_cat
),
  RegionalTotals AS (
  SELECT region, SUM(total_sales) AS total_region_sales
  FROM SalesByRegion
  GROUP BY region
) SELECT * FROM RegionalTotals;

WITH ProductSales AS (
  SELECT product_id, SUM(sales) AS total_sales
  FROM sales_data
  GROUP BY product_id
) SELECT product_id, total_sales, product_category
FROM (
  SELECT product_id, total_sales, product_category, ROW_NUMBER() OVER (PARTITION BY product_category ORDER BY total_sales DESC) AS rank
  FROM ProductSales
) AS subquery
WHERE rank <= 10;

