func main() {
  ctx := context.Background()
  var wg sync.WaitGroup
  tasks := 10
  workers := 5
  pool := &sync.Pool{
    New: func() interface{} {
      return &workerTask{}
    },
  }
  for i := 0; i < workers; i++ {
    pool.Put(&workerTask{
      id:       i,
      completed: make(chan struct{}),
    })
  }
  for i := 0; i < tasks; i++ {
    wg.Add(1)
    task := pool.Get().(*workerTask)
    go func() {
      defer pool.Put(task)
      defer wg.Done()
      // task logic
      task.completed <- struct{}{}
    }()
  }
  wg.Wait()
}

type worker struct {
  stopChan chan struct{}
}
func (w *worker) Run(tasks <-chan Task) {
  for task := range tasks {
    // process task
    if w.stopChan != nil && len(w.stopChan) > 0 {
      return
    }
  }
}

