  for i := 0; i < 10; i++ {
    wg.Add(1)
    go func() {
      defer wg.Done()
      // worker logic
    }()
  }
  wg.Wait()
}

func worker(tasks <-chan Task, stopChan chan struct{}) {
  defer func() {
    if r := recover(); r != nil {
